/**
 * SPEC-046: ParticipantsChecklist — la lista de Checkbox de participantes
 * compartida por los cuatro flujos (GroupInterviewFormDialog,
 * InterviewFormDialog, EditCaptureDialog y AssignCompanySheet). Marcar añade
 * al FINAL (el orden de marcado es el orden persistido en contactIds);
 * desmarcar filtra; sin contactos, mensaje muted del caller.
 * Generated by QA Dev agent.
 *
 * Componente aislado (frontera: prop onChange); sin bridge.
 */
import { render, screen, within } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { ParticipantsChecklist } from '@/components/interviews/ParticipantsChecklist'
import type { Contact } from '@/types/domain'

const JANE: Contact = {
  id: 'ct-1',
  companyId: 'c-1',
  name: 'Jane Doe',
  position: 'CTO',
  linkedinUrl: null,
  context: null,
  createdAt: '2026-07-03T12:00:00.000Z',
  updatedAt: '2026-07-03T12:00:00.000Z'
}

const JOHN: Contact = {
  ...JANE,
  id: 'ct-2',
  name: 'John Smith',
  position: null
}

let onChange: ReturnType<typeof vi.fn<(selectedIds: string[]) => void>>

beforeEach(() => {
  vi.clearAllMocks()
  onChange = vi.fn<(selectedIds: string[]) => void>()
})

describe('ParticipantsChecklist', () => {
  // SPEC-046 · AC-21 (componente compartido): una fila Checkbox por contacto
  // con su nombre y la posición muted si existe; los seleccionados, marcados
  it('renders one checkbox row per contact with its name and muted position, checking the selected ones', () => {
    render(
      <ParticipantsChecklist
        contacts={[JANE, JOHN]}
        selectedIds={['ct-2']}
        onChange={onChange}
        emptyMessage="Esta empresa no tiene contactos"
      />
    )

    const container = screen.getByTestId('interview-participants')
    expect(within(container).getByRole('checkbox', { name: /Jane Doe/ })).not.toBeChecked()
    expect(within(container).getByRole('checkbox', { name: /John Smith/ })).toBeChecked()
    // Posición muted solo cuando existe
    expect(within(container).getByText('CTO')).toHaveClass('text-muted-foreground')
  })

  // SPEC-046 · AC-15/AC-21 (orden de marcado): marcar AÑADE al final de la
  // selección (el orden de marcado es el orden persistido en contactIds)
  it('calls onChange appending the newly checked contact at the end of the selection', async () => {
    const user = userEvent.setup()
    render(
      <ParticipantsChecklist
        contacts={[JANE, JOHN]}
        selectedIds={['ct-2']}
        onChange={onChange}
        emptyMessage="Esta empresa no tiene contactos"
      />
    )

    await user.click(screen.getByRole('checkbox', { name: /Jane Doe/ }))

    // John estaba marcado primero: Jane se añade DETRÁS (no orden de alta)
    expect(onChange).toHaveBeenCalledWith(['ct-2', 'ct-1'])
  })

  // SPEC-046 · AC-21 (desmarcado): quitar un participante filtra su id
  // conservando el orden del resto
  it('calls onChange filtering out the unchecked contact keeping the remaining order', async () => {
    const user = userEvent.setup()
    render(
      <ParticipantsChecklist
        contacts={[JANE, JOHN]}
        selectedIds={['ct-2', 'ct-1']}
        onChange={onChange}
        emptyMessage="Esta empresa no tiene contactos"
      />
    )

    await user.click(screen.getByRole('checkbox', { name: /John Smith/ }))

    expect(onChange).toHaveBeenCalledWith(['ct-1'])
  })

  // SPEC-046 · AC-11 (componente): sin contactos, el mensaje muted del caller
  it('renders the muted empty message when there are no contacts', () => {
    render(
      <ParticipantsChecklist
        contacts={[]}
        selectedIds={[]}
        onChange={onChange}
        emptyMessage="Esta empresa no tiene contactos"
      />
    )

    const container = screen.getByTestId('interview-participants')
    expect(within(container).getByText('Esta empresa no tiene contactos')).toHaveClass(
      'text-muted-foreground'
    )
    expect(within(container).queryAllByRole('checkbox')).toHaveLength(0)
  })
})
